 75→            strokeLinecap="round"
 76→          />
 77→        </svg>
 78→      );
 79→  }
 80→}
 81→
 82→export function Toast({
 83→  style,
 84→  title,
 85→  message,
 86→  exiting,
 87→  onDismiss,
 88→}: ToastProps) {
 89→  const isError = style === 'error';
 90→  return (
 91→    <div
 92→      className={`toast toast--${style}${exiting ? ' toast--exiting' : ''}`}
 93→      onClick={onDismiss}
 94→      role={isError ? 'alert' : 'status'}
 95→      aria-live={isError ? 'assertive' : 'polite'}
 96→      aria-atomic="true"
 97→    >
 98→      <ToastIcon style={style} />
 99→      <div className="toast__content">
100→        <span className="toast__title">{title}</span>
101→        {message && <span className="toast__message">{message}</span>}
102→      </div>
103→    </div>
104→  );
105→}
