185→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
186→  const [formErrors, setFormErrors] = useState<
187→    Partial<Record<keyof SnippetFormState, string>>
188→  >({});
189→
190→  const handleSubmit = useCallback(() => {
191→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
192→    if (!snippetForm.name.trim()) {
193→      errors.name = 'Name is required';
194→    }
195→    if (!snippetForm.snippet.trim()) {
196→      errors.snippet = 'Snippet content is required';
197→    }
198→    setFormErrors(errors);
199→    if (Object.keys(errors).length > 0) {
200→      return;
201→    }
202→    onSubmit(snippetForm);
203→  }, [
204→    snippetForm,
205→    onSubmit,
206→  ]);
207→
208→  useEffect(() => {
