239→            ...prev,
240→            keyword: v,
241→          }))
242→        }
243→        placeholder="e.g. !sig"
244→        description="Type this to expand the snippet"
245→      />
246→      <FormDropdown
247→        label="Category"
248→        value={snippetForm.category}
249→        onChange={v =>
250→          setSnippetForm(prev => ({
251→            ...prev,
252→            category: v,
